div.script:

(async function autoFetchAndRender() {
  const TARGET_URL = 'https://cdn.jsdelivr.net/gh/zaka13alt/singlesvgs@HEAD/me/simple.html'; 

  try {
    // Fetch the HTML without user input
    const response = await fetch(TARGET_URL);

    if (response.ok) {
      const htmlContent = await response.text();

      // Inject the scraped HTML directly into the srcdoc of the iframe
      const iframe = document.getElementById('viewer');
      iframe.srcdoc = htmlContent;
    } else {
      console.error('Failed to fetch the URL, status:', response.status);
    }
  } catch (error) {
    console.error('Fetch operation failed:', error);
  }
})();
